def top_k_with_ties(values, k):
    if k <= 0 or not values:
        return []
    order = sorted(range(len(values)), key=lambda i: (-values[i], i))
    chosen = order[:min(k, len(values))]
    return sorted(chosen)

def is_reachable(graph, start, end):
    if start == end:
        return True
    visited = {start}
    stack = [start]
    while stack:
        node = stack.pop()
        for nxt in graph.get(node, []):
            if nxt == end:
                return True
            if nxt not in visited:
                visited.add(nxt)
                stack.append(nxt)
    return False

def has_cycle(graph):
    WHITE, GRAY, BLACK = 0, 1, 2
    color = {node: WHITE for node in graph}

    def visit(node):
        color[node] = GRAY
        for nxt in graph.get(node, []):
            c = color.get(nxt, WHITE)
            if c == GRAY:
                return True
            if c == WHITE and visit(nxt):
                return True
        color[node] = BLACK
        return False

    for node in list(graph.keys()):
        if color.get(node, WHITE) == WHITE:
            if visit(node):
                return True
    return False

def tree_depth(parent):
    nodes = set(parent.keys()) | set(parent.values())
    depth_cache = {}

    def depth(node):
        if node not in parent:
            return 0
        if node in depth_cache:
            return depth_cache[node]
        d = 1 + depth(parent[node])
        depth_cache[node] = d
        return d

    return {node: depth(node) for node in nodes}

def subtree_sizes(parent):
    nodes = set(parent.keys()) | set(parent.values())
    children = {n: [] for n in nodes}
    for child, p in parent.items():
        children[p].append(child)
    sizes = {}

    def size(node):
        if node in sizes:
            return sizes[node]
        s = 1 + sum(size(c) for c in children[node])
        sizes[node] = s
        return s

    for n in nodes:
        size(n)
    return sizes

def bounding_box(points):
    if not points:
        raise ValueError("points must not be empty")
    xs = [p[0] for p in points]
    ys = [p[1] for p in points]
    return (min(xs), min(ys), max(xs), max(ys))

def median_lower(values):
    if not values:
        raise ValueError("values must not be empty")
    s = sorted(values)
    n = len(s)
    if n % 2 == 1:
        return s[n // 2]
    return s[n // 2 - 1]

def mode_smallest(values):
    if not values:
        raise ValueError("values must not be empty")
    counts = {}
    for v in values:
        counts[v] = counts.get(v, 0) + 1
    best = None
    best_count = -1
    for v in sorted(counts):
        if counts[v] > best_count:
            best_count = counts[v]
            best = v
    return best

def trimmed_sum(values, k):
    if k < 0:
        raise ValueError("k must be non-negative")
    s = sorted(values)
    n = len(s)
    if 2 * k >= n:
        return 0
    return sum(s[k:n - k])

def smallest_gap(values):
    if len(values) < 2:
        raise ValueError("need at least two values")
    s = sorted(values)
    return min(s[i + 1] - s[i] for i in range(len(s) - 1))

